import React, { useState } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { format } from 'date-fns';
import { vi } from 'date-fns/locale';
import './NotesPage.css';

const SAMPLE_NOTES = [
  {
    id: uuidv4(),
    title: 'Tóm tắt bài giảng AI - Chương 3',
    content: 'Machine Learning là một nhánh của AI cho phép máy tính học từ dữ liệu.\n\n- Supervised Learning: học có giám sát\n- Unsupervised Learning: học không giám sát\n- Reinforcement Learning: học tăng cường',
    subject: 'Trí tuệ Nhân tạo',
    createdAt: new Date().toISOString(),
  },
  {
    id: uuidv4(),
    title: 'Open Claw - Các use case chính',
    content: 'Open Claw có thể:\n1. Tự động hoá thao tác trình duyệt\n2. Thu thập thông tin từ nhiều nền tảng\n3. Hỗ trợ quản lý tác vụ thông minh\n\nỨng dụng cho sinh viên: quản lý bài tập, nhắc nhở hạn nộp.',
    subject: 'Công nghệ Phần mềm',
    createdAt: new Date().toISOString(),
  },
];

export default function NotesPage({ tasks }) {
  const [notes, setNotes] = useState(() => {
    try { return JSON.parse(localStorage.getItem('tdtapp_notes')) || SAMPLE_NOTES; }
    catch { return SAMPLE_NOTES; }
  });
  const [filterSubject, setFilterSubject] = useState('all');
  const [editNote, setEditNote] = useState(null);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ title: '', content: '', subject: '' });

  const subjects = ['all', ...new Set([...tasks.map(t => t.subject), ...notes.map(n => n.subject)])];

  const filtered = notes.filter(n => filterSubject === 'all' || n.subject === filterSubject);

  function saveNotes(updated) {
    setNotes(updated);
    localStorage.setItem('tdtapp_notes', JSON.stringify(updated));
  }

  function handleSave() {
    if (!form.title.trim()) return;
    if (editNote) {
      saveNotes(notes.map(n => n.id === editNote.id ? { ...n, ...form } : n));
    } else {
      saveNotes([{ id: uuidv4(), ...form, createdAt: new Date().toISOString() }, ...notes]);
    }
    setShowForm(false);
    setEditNote(null);
    setForm({ title: '', content: '', subject: '' });
  }

  function handleEdit(note) {
    setForm({ title: note.title, content: note.content, subject: note.subject });
    setEditNote(note);
    setShowForm(true);
  }

  function handleDelete(id) { saveNotes(notes.filter(n => n.id !== id)); }

  function handleCancel() {
    setShowForm(false);
    setEditNote(null);
    setForm({ title: '', content: '', subject: '' });
  }

  return (
    <div className="page-container animate-fade-in">
      <div className="page-header">
        <div className="page-title">
          <h1>📝 Ghi chép</h1>
          <p>Ghi chú bài học và tóm tắt kiến thức theo từng môn</p>
        </div>
        <button className="btn btn-primary" onClick={() => { setShowForm(true); setEditNote(null); setForm({ title: '', content: '', subject: '' }); }}>
          ＋ Ghi chú mới
        </button>
      </div>

      {/* Add/Edit form */}
      {showForm && (
        <div className="note-form card animate-slide-up">
          <h3 style={{ marginBottom: 16 }}>{editNote ? '✏️ Chỉnh sửa ghi chú' : '📝 Ghi chú mới'}</h3>
          <div className="flex flex-col gap-3">
            <div className="grid-2" style={{ gap: 12 }}>
              <div className="form-group">
                <label className="form-label">Tiêu đề *</label>
                <input className="form-input" placeholder="Tiêu đề ghi chú..." value={form.title} onChange={e => setForm(p => ({ ...p, title: e.target.value }))} />
              </div>
              <div className="form-group">
                <label className="form-label">Môn học</label>
                <select className="form-select" value={form.subject} onChange={e => setForm(p => ({ ...p, subject: e.target.value }))}>
                  <option value="">Chọn môn...</option>
                  {tasks.map(t => t.subject).filter((v, i, a) => a.indexOf(v) === i).map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            </div>
            <div className="form-group">
              <label className="form-label">Nội dung</label>
              <textarea className="form-textarea" rows={8} placeholder="Ghi chú nội dung bài học, điểm quan trọng cần nhớ..." value={form.content} onChange={e => setForm(p => ({ ...p, content: e.target.value }))} />
            </div>
          </div>
          <div className="flex gap-3" style={{ marginTop: 16 }}>
            <button className="btn btn-primary" onClick={handleSave}>💾 Lưu</button>
            <button className="btn btn-secondary" onClick={handleCancel}>Huỷ</button>
          </div>
        </div>
      )}

      {/* Filter */}
      <div className="doc-subject-tabs" style={{ marginBottom: 24 }}>
        {subjects.map(s => (
          <button key={s} className={`filter-btn ${filterSubject === s ? 'filter-btn--active' : ''}`} onClick={() => setFilterSubject(s)}>
            {s === 'all' ? '📚 Tất cả' : s}
          </button>
        ))}
      </div>

      {/* Notes grid */}
      {filtered.length === 0 ? (
        <div className="empty-state">
          <div className="empty-state-icon">📓</div>
          <h3>Chưa có ghi chú nào</h3>
          <p>Nhấn "Ghi chú mới" để bắt đầu ghi lại kiến thức bài học</p>
        </div>
      ) : (
        <div className="notes-grid">
          {filtered.map(note => (
            <div key={note.id} className="note-card animate-slide-up">
              <div className="note-card-header">
                {note.subject && <span className="note-card-subject">{note.subject}</span>}
                <div className="note-card-actions">
                  <button className="btn btn-icon btn-secondary" onClick={() => handleEdit(note)}>✏️</button>
                  <button className="btn btn-icon btn-danger" onClick={() => handleDelete(note.id)}>🗑️</button>
                </div>
              </div>
              <h3 className="note-card-title">{note.title}</h3>
              <p className="note-card-content">{note.content}</p>
              <span className="note-card-date">
                {format(new Date(note.createdAt), "dd/MM/yyyy", { locale: vi })}
              </span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
